"use client";

import { AnimatePresence, motion } from "framer-motion";
import { useEffect, useMemo, useState } from "react";

const bootLines = ["[BOOT] Core ignition", "[LINK] Neural mesh online", "[READY] OZMOZ protocol active"];
const heroText = "Revive Dead Codebases.";
const tickerItems = [
  "NODE-01 CONNECTED",
  "NEURAL ENCRYPTION ACTIVE",
  "ZURICH LAB SYNCED",
  "MISSION QUEUE STABLE",
  "TELEMETRY LOCKED"
];

const operations = [
  { title: "Legacy Billing Resurrection", status: "Syncing", bounty: "$42,000" },
  { title: "Abandoned Browser Extension", status: "Live", bounty: "$12,500" },
  { title: "Dead CRM Core Refactor", status: "Live", bounty: "$31,800" }
];

const leaderboard = [
  { name: "Aria Holt", rank: "Grand Master", score: "9,420" },
  { name: "Mason Vale", rank: "Master Architect", score: "8,910" },
  { name: "Nora Ives", rank: "Master Architect", score: "8,140" }
];

export default function Home() {
  const [bootIndex, setBootIndex] = useState(0);
  const [typingIndex, setTypingIndex] = useState(0);
  const [query, setQuery] = useState("");
  const [analyzing, setAnalyzing] = useState(false);
  const [analysis, setAnalysis] = useState<null | {
    debt: string;
    path: string;
    gain: string;
    sec: string;
  }>(null);
  const [alertVisible, setAlertVisible] = useState(false);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [restrictedOpen, setRestrictedOpen] = useState(false);
  const [approvedOpen, setApprovedOpen] = useState(false);
  const [chatOpen, setChatOpen] = useState(false);
  const [cpuLoad, setCpuLoad] = useState(37);
  const [memoryUsage, setMemoryUsage] = useState(62);
  const [latency, setLatency] = useState(1);
  const [nodes, setNodes] = useState(45000);
  const [cursor, setCursor] = useState({ x: 0, y: 0 });
  const [magnet, setMagnet] = useState<null | { x: number; y: number }>(null);

  const typedHero = useMemo(() => heroText.slice(0, typingIndex), [typingIndex]);

  useEffect(() => {
    if (bootIndex >= bootLines.length) {
      return;
    }

    const timer = setTimeout(() => {
      setBootIndex((prev) => prev + 1);
    }, 520);

    return () => clearTimeout(timer);
  }, [bootIndex]);

  useEffect(() => {
    if (bootIndex < bootLines.length || typingIndex >= heroText.length) {
      return;
    }

    const timer = setTimeout(() => {
      setTypingIndex((prev) => prev + 1);
    }, 42);

    return () => clearTimeout(timer);
  }, [bootIndex, typingIndex]);

  useEffect(() => {
    const telemetryTimer = setInterval(() => {
      setCpuLoad(31 + Math.floor(Math.random() * 29));
      setMemoryUsage(52 + Math.floor(Math.random() * 31));
      setLatency(1 + Math.floor(Math.random() * 4));
      setNodes(44900 + Math.floor(Math.random() * 300));
    }, 2000);

    return () => clearInterval(telemetryTimer);
  }, []);

  useEffect(() => {
    const onMouseMove = (event: MouseEvent) => {
      setCursor({ x: event.clientX, y: event.clientY });
    };

    window.addEventListener("mousemove", onMouseMove);
    return () => window.removeEventListener("mousemove", onMouseMove);
  }, []);

  const glowX = magnet?.x ?? cursor.x;
  const glowY = magnet?.y ?? cursor.y;

  const handleAnalyze = () => {
    if (!query.includes("github.com") && query.length < 6) {
      setAlertVisible(true);
      setAnalysis(null);
      return;
    }

    setAnalyzing(true);
    setAlertVisible(false);
    setAnalysis(null);

    setTimeout(() => {
      setAnalyzing(false);
      setAnalysis({
        debt: "High Critical",
        path: "Rust Migration",
        gain: "+42% Speed",
        sec: "ZKP Verified"
      });
    }, 1800);
  };

  const handlePublish = () => {
    if (!isAuthenticated) {
      setRestrictedOpen(true);
      return;
    }
    setApprovedOpen(true);
  };

  const magneticProps = {
    onMouseEnter: (event: React.MouseEvent<HTMLElement>) => {
      const rect = event.currentTarget.getBoundingClientRect();
      setMagnet({ x: rect.left + rect.width / 2, y: rect.top + rect.height / 2 });
    },
    onMouseLeave: () => setMagnet(null)
  };

  return (
    <main className="relative min-h-screen cursor-none overflow-hidden bg-[#01040b] text-slate-100">
      <motion.div
        className="pointer-events-none fixed z-50 h-2 w-2 rounded-full bg-emerald-300"
        animate={{ x: cursor.x - 4, y: cursor.y - 4 }}
        transition={{ type: "spring", damping: 40, stiffness: 600, mass: 0.1 }}
      />
      <motion.div
        className="pointer-events-none fixed z-40 h-16 w-16 rounded-full bg-emerald-300/20"
        animate={{ x: glowX - 32, y: glowY - 32, scale: magnet ? 1.28 : 1 }}
        transition={{ type: "spring", damping: 28, stiffness: 240 }}
        style={{ boxShadow: "0 0 50px rgba(74,222,128,0.35)" }}
      />

      <div className="pointer-events-none absolute inset-0 bg-[radial-gradient(circle_at_50%_10%,rgba(16,185,129,0.08),transparent_40%)]" />
      <div className="pointer-events-none absolute inset-0 opacity-25 [background-image:linear-gradient(to_right,rgba(100,116,139,0.2)_1px,transparent_1px),linear-gradient(to_bottom,rgba(100,116,139,0.16)_1px,transparent_1px)] [background-size:34px_34px]" />

      <div className="relative z-10 mx-auto flex w-full max-w-7xl flex-col gap-16 px-6 py-8 font-mono sm:px-10 lg:px-16">
        <header className="rounded-xl border border-emerald-500/35 bg-[#07101f]/85 p-4 backdrop-blur">
          <div className="flex flex-wrap items-center justify-between gap-4">
            <div className="flex items-center gap-3">
              <motion.div
                className="rounded-full border border-emerald-300/50 bg-emerald-300/10 p-2"
                animate={{ opacity: [0.45, 1, 0.45], scale: [1, 1.04, 1] }}
                transition={{ duration: 3.2, repeat: Infinity, ease: "easeInOut" }}
                style={{ boxShadow: "0 0 24px rgba(74,222,128,0.45)" }}
              >
                <svg viewBox="0 0 24 24" className="h-5 w-5 text-emerald-200" fill="currentColor">
                  <path d="M13 2 4 14h6l-1 8 9-12h-6l1-8Z" />
                </svg>
              </motion.div>
              <div>
                <p className="text-lg font-semibold uppercase tracking-[0.25em]">OZMOZ</p>
                <p className="text-[10px] uppercase tracking-[0.18em] text-emerald-300">Revival Labs</p>
              </div>
            </div>
            <nav className="flex flex-wrap items-center gap-5 text-[11px] uppercase tracking-[0.18em] text-slate-300">
              {["Operations", "Leaderboard", "Lab Reports", "FAQ"].map((item) => (
                <button
                  key={item}
                  {...magneticProps}
                  className="group relative transition hover:text-emerald-200"
                >
                  {item}
                  <span className="absolute -bottom-1 left-0 h-px w-0 bg-emerald-300 transition-all duration-300 group-hover:w-full" />
                </button>
              ))}
            </nav>
          </div>
          <div className="mt-4 overflow-hidden rounded border border-slate-700 bg-black/70 py-2">
            <motion.div
              className="flex min-w-max gap-8 px-4 text-[10px] uppercase tracking-[0.16em] text-emerald-300"
              animate={{ x: ["0%", "-50%"] }}
              transition={{ duration: 16, ease: "linear", repeat: Infinity }}
            >
              {[...tickerItems, ...tickerItems].map((item, idx) => (
                <span key={`${item}-${idx}`}>{item}</span>
              ))}
            </motion.div>
          </div>
        </header>

        <section className="grid gap-8 lg:grid-cols-[1.1fr_1fr]">
          <div className="space-y-4 rounded-xl border border-slate-700 bg-[#050b18]/80 p-6">
            <p className="text-xs uppercase tracking-[0.2em] text-emerald-300">Entry Sequence</p>
            <div className="space-y-2 text-sm text-slate-300">
              {bootLines.slice(0, bootIndex).map((line, idx) => (
                <p key={line + idx}>{line}</p>
              ))}
            </div>
          </div>

          <div className="rounded-xl border border-slate-700 bg-[#030712]/85 p-6">
            <p className="text-xs uppercase tracking-[0.2em] text-emerald-300">Core Manifest</p>
            <h2 className="mt-4 min-h-16 text-4xl font-semibold italic text-white sm:text-5xl">
              {typedHero}
              <span className="ml-1 inline-block text-emerald-300">|</span>
            </h2>
            <p className="mt-4 text-sm leading-relaxed text-slate-300">Clear missions. Visible impact. Winnable execution windows.</p>
            <div className="mt-6 grid grid-cols-3 gap-3 text-center">
              <div>
                <p className="text-2xl font-semibold text-white">42K+</p>
                <p className="text-[11px] uppercase tracking-[0.14em] text-slate-400">Engineers</p>
              </div>
              <div>
                <p className="text-2xl font-semibold text-white">$120M</p>
                <p className="text-[11px] uppercase tracking-[0.14em] text-slate-400">Bounty Given</p>
              </div>
              <div>
                <p className="text-2xl font-semibold text-white">85K+</p>
                <p className="text-[11px] uppercase tracking-[0.14em] text-slate-400">Projects</p>
              </div>
            </div>
          </div>
        </section>

        <section className="rounded-2xl border border-slate-700 bg-white/5 p-6 backdrop-blur-xl">
          <AnimatePresence>
            {alertVisible && (
              <motion.div
                className="mb-4 flex items-center justify-between rounded border border-red-500/50 bg-red-500/10 px-3 py-2 text-xs text-red-300"
                initial={{ opacity: 0, y: -8 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: -12, scale: 0.98, filter: "blur(5px)" }}
              >
                <span>Repo Not Found.</span>
                <button {...magneticProps} onClick={() => setAlertVisible(false)}>
                  X
                </button>
              </motion.div>
            )}
          </AnimatePresence>

          <p className="text-xs uppercase tracking-[0.2em] text-emerald-300">Technical Mission Panel</p>
          <h3 className="mt-2 text-2xl font-semibold text-white">Neural Search</h3>
          <div className="mt-4 flex flex-col gap-3 sm:flex-row">
            <input
              value={query}
              onChange={(event) => setQuery(event.target.value)}
              placeholder="Paste repository URL or mission name..."
              className="flex-1 rounded-lg border border-slate-600 bg-black/45 px-4 py-3 text-sm text-white outline-none placeholder:text-slate-500 focus:border-emerald-400"
            />
            <button
              {...magneticProps}
              onClick={handleAnalyze}
              className="rounded-lg bg-emerald-400 px-4 py-3 text-sm font-semibold uppercase tracking-[0.12em] text-black"
            >
              {analyzing ? (
                <span className="inline-flex items-center gap-2">
                  <motion.span
                    className="inline-block h-3 w-3 rounded-full border-2 border-black border-t-transparent"
                    animate={{ rotate: 360 }}
                    transition={{ duration: 0.9, repeat: Infinity, ease: "linear" }}
                  />
                  Analyzing
                </span>
              ) : (
                "Neural Analyze"
              )}
            </button>
          </div>

          <AnimatePresence>
            {analysis && (
              <motion.div
                className="mt-5 grid gap-3 sm:grid-cols-2 lg:grid-cols-4"
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0 }}
              >
                {[
                  { k: "DEBT", v: analysis.debt },
                  { k: "PATH", v: analysis.path },
                  { k: "GAIN", v: analysis.gain },
                  { k: "SEC", v: analysis.sec }
                ].map((item) => (
                  <div key={item.k} className="rounded-lg border border-emerald-400/60 bg-emerald-500/10 p-3">
                    <p className="text-[11px] uppercase tracking-[0.14em] text-emerald-300">{item.k}</p>
                    <p className="mt-1 text-sm text-white">{item.v}</p>
                  </div>
                ))}
              </motion.div>
            )}
          </AnimatePresence>

          <div className="mt-6 flex flex-wrap items-center gap-3">
            <button
              {...magneticProps}
              onClick={handlePublish}
              className="rounded-md border border-emerald-400/60 bg-emerald-500/15 px-5 py-3 text-xs uppercase tracking-[0.16em] text-emerald-200"
            >
              Publish Protocol
            </button>
            <button
              {...magneticProps}
              onClick={() => setIsAuthenticated((prev) => !prev)}
              className="rounded-md border border-slate-600 px-4 py-3 text-xs uppercase tracking-[0.14em] text-slate-300"
            >
              {isAuthenticated ? "Sign Out Simulation" : "Sign In Simulation"}
            </button>
            <p className="text-[11px] uppercase tracking-[0.12em] text-slate-500">
              Auth Status: {isAuthenticated ? "Authorized" : "Guest"}
            </p>
          </div>
        </section>

        <section className="space-y-5">
          <h3 className="text-xl font-semibold uppercase tracking-[0.12em] text-white">Live Operations</h3>
          <div className="grid gap-4 lg:grid-cols-3">
            {operations.map((item) => (
              <article
                key={item.title}
                className="group rounded-xl border border-slate-700 bg-white/5 p-4 transition duration-300 hover:-translate-y-1 hover:border-emerald-400/70 hover:shadow-[0_0_24px_rgba(74,222,128,0.25)]"
              >
                <p className="text-[11px] uppercase tracking-[0.14em] text-emerald-300">{item.status}</p>
                <p className="mt-2 text-base text-white">{item.title}</p>
                <p className="mt-4 text-sm text-slate-300">Bounty Pool: {item.bounty}</p>
              </article>
            ))}
          </div>
        </section>

        <section className="grid gap-6 lg:grid-cols-2">
          <div className="rounded-xl border border-slate-700 bg-white/5 p-5">
            <h4 className="text-lg font-semibold uppercase tracking-[0.12em] text-white">Elite Leaderboard</h4>
            <div className="mt-4 space-y-3">
              {leaderboard.map((item, idx) => (
                <div key={item.name} className="flex items-center justify-between rounded border border-slate-700 bg-black/30 px-3 py-2">
                  <p className="text-sm text-white">
                    {idx + 1}. {item.name}
                  </p>
                  <p className="text-xs uppercase tracking-[0.12em] text-emerald-300">
                    {item.rank} • {item.score}
                  </p>
                </div>
              ))}
            </div>
          </div>

          <div className="rounded-xl border border-slate-700 bg-white/5 p-5">
            <h4 className="text-lg font-semibold uppercase tracking-[0.12em] text-white">Lab Reports</h4>
            <div className="mt-4 flex items-center gap-3">
              <div className="flex h-12 w-12 items-center justify-center rounded-full border border-emerald-400/70 text-xs text-emerald-200">LVL 12</div>
              <div>
                <p className="text-sm text-white">Architect Profile</p>
                <p className="text-xs uppercase tracking-[0.12em] text-slate-400">Mission Synchronization Active</p>
              </div>
            </div>
            <p className="mt-4 text-sm text-emerald-300">Syncing active missions on neural radar...</p>
          </div>
        </section>
      </div>

      <footer className="relative z-10 mt-8 border-t border-emerald-500/20 bg-[#020b1a] px-6 py-10 font-mono sm:px-10 lg:px-16">
        <div className="mx-auto grid w-full max-w-7xl gap-8 text-sm text-slate-300 md:grid-cols-4">
          <div>
            <p className="mb-3 text-xs uppercase tracking-[0.2em] text-emerald-300">Solutions</p>
            <ul className="space-y-2">
              <li>Mission Curation</li>
              <li>Codebase Diagnostics</li>
              <li>Revival Roadmaps</li>
            </ul>
          </div>
          <div>
            <p className="mb-3 text-xs uppercase tracking-[0.2em] text-emerald-300">Resources</p>
            <ul className="space-y-2">
              <li>Playbooks</li>
              <li>Architecture Notes</li>
              <li>AI Starter Packs</li>
            </ul>
          </div>
          <div>
            <p className="mb-3 text-xs uppercase tracking-[0.2em] text-emerald-300">Corporate</p>
            <ul className="space-y-2">
              <li>About Revival Labs</li>
              <li>Careers</li>
              <li>Partnerships</li>
            </ul>
          </div>
          <div>
            <p className="mb-3 text-xs uppercase tracking-[0.2em] text-emerald-300">Compliance</p>
            <ul className="space-y-2">
              <li>Security Policy</li>
              <li>Privacy</li>
              <li>Terms</li>
            </ul>
          </div>
        </div>

        <div className="mx-auto mt-8 flex w-full max-w-7xl flex-col gap-2 rounded-lg border border-slate-700 bg-[#020611] px-4 py-3 text-xs uppercase tracking-[0.14em] text-slate-300 sm:flex-row sm:items-center sm:justify-between">
          <p>System Telemetry</p>
          <div className="flex flex-wrap gap-5">
            <p>CPU Load: {cpuLoad}%</p>
            <p>Memory Usage: {memoryUsage}%</p>
            <p>Latency: {latency}ms</p>
            <p>Nodes: {nodes}</p>
            <p className="text-emerald-300">Revival Status: Active</p>
          </div>
        </div>
        <p className="mx-auto mt-4 w-full max-w-7xl text-[10px] uppercase tracking-[0.2em] text-slate-500">
          Secured by Neural Encryption
        </p>
      </footer>

      <button
        {...magneticProps}
        onClick={() => setChatOpen((prev) => !prev)}
        className="fixed bottom-5 right-5 z-30 rounded-full border border-emerald-300/60 bg-emerald-300/15 p-3 text-emerald-200 shadow-[0_0_24px_rgba(74,222,128,0.4)] transition hover:bg-emerald-300/25"
        aria-label="Open neural link chat"
      >
        <svg viewBox="0 0 24 24" className="h-6 w-6" fill="currentColor" aria-hidden="true">
          <path d="M2 12c2.4-4.2 5.7-6.3 10-6.3S19.6 7.8 22 12c-2.4 4.2-5.7 6.3-10 6.3S4.4 16.2 2 12Zm10 2.8a2.8 2.8 0 1 0 0-5.6 2.8 2.8 0 0 0 0 5.6Z" />
        </svg>
      </button>

      <AnimatePresence>
        {chatOpen && (
          <motion.div
            className="fixed bottom-20 right-5 z-30 w-80 rounded-xl border border-emerald-400/50 bg-[#020915]/95 p-4"
            initial={{ opacity: 0, y: 18 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: 18 }}
          >
            <p className="text-xs uppercase tracking-[0.16em] text-emerald-300">Neural Link</p>
            <div className="mt-3 space-y-2 text-sm">
              <p className="text-white">System: Welcome back, Architect.</p>
              <p className="text-emerald-300">Architect: Start mission broadcast.</p>
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      <AnimatePresence>
        {restrictedOpen && (
          <motion.div
            className="fixed inset-0 z-40 flex items-center justify-center bg-black/70 p-6"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
          >
            <div className="w-full max-w-md rounded-xl border border-red-400/40 bg-[#0b0b12] p-6 text-center">
              <p className="text-xs uppercase tracking-[0.18em] text-red-300">Access Restricted</p>
              <p className="mt-3 text-sm text-slate-300">
                You need to sign in before publishing a protocol.
              </p>
              <button
                {...magneticProps}
                onClick={() => setRestrictedOpen(false)}
                className="mt-5 rounded-md border border-red-400/50 px-4 py-2 text-xs uppercase tracking-[0.14em] text-red-200"
              >
                Close
              </button>
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      <AnimatePresence>
        {approvedOpen && (
          <motion.div
            className="fixed inset-0 z-50 flex flex-col items-center justify-center bg-white text-black"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
          >
            <motion.div
              className="flex h-24 w-24 items-center justify-center rounded-full bg-emerald-400 text-5xl text-white"
              animate={{ scale: [1, 1.08, 1] }}
              transition={{ duration: 1.4, repeat: Infinity, ease: "easeInOut" }}
            >
              ✓
            </motion.div>
            <p className="mt-5 text-2xl font-semibold">Protocol Approved</p>
            <button
              {...magneticProps}
              onClick={() => setApprovedOpen(false)}
              className="mt-6 rounded-md border border-black/30 px-4 py-2 text-xs uppercase tracking-[0.16em]"
            >
              Return to Lab
            </button>
          </motion.div>
        )}
      </AnimatePresence>
    </main>
  );
}
